class Solution:
    def minAddToMakeValid(self, s: str) -> int:
        # Simulate by tracking a stack and counting unmatched
        stack = []
        unmatched_close = 0
        for c in s:
            if c == '(':
                stack.append(c)
            else:
                if stack:
                    stack.pop()
                else:
                    unmatched_close += 1
        return len(stack) + unmatched_close

