var minAddToMakeValid = function(s) {
    let openCnt = 0, closeCnt = 0;
    for (const c of s) {
        if (c === '(') {
            openCnt++;
        } else {
            if (openCnt > 0) {
                openCnt--;
            } else {
                closeCnt++;
            }
        }
    }
    return openCnt + closeCnt;
};
